import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";

export function Login() {
  const [email, setEmail] = useState("");
  const [lozinkaHash, setLozinka] = useState("");
  const imeRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

  // Funkcija za login (razlikuje gosta i recepcionara po role parametru)
  const handleSubmit = async (e, role) => {
    e.preventDefault();

    try {
      // Backend endpoint zavisi od tipa korisnika
      const url =
        role === "admin"
          ? `http://localhost:8080/receptionists/login/${email}/${lozinkaHash}`
          : `http://localhost:8080/guests/login/${email}/${lozinkaHash}`;

      const response = await fetch(url, { method: "GET" });

      if (response.ok) {
        const data = await response.json();

        if (role === "gost") {
          const guest = data.data.guest;
          document.cookie = `userEmail=${guest.email}; path=/;`;
          document.cookie = `userId=${guest.idGost}; path=/;`;
          navigate("/");
        } else {
          const receptionist = data.data.receptionist; // <-- ovde je promena
          document.cookie = `userEmail=${receptionist.korisnickoIme}; path=/;`;
          document.cookie = `userId=${receptionist.idRecepcionar}; path=/;`;
          navigate("/recepcionar");
        }
      } else {
        alert("Pogrešno uneti podaci!");
      }
    } catch (error) {
      console.error("Greška prilikom login-a:", error);
      alert("Server nije dostupan.");
    }
  };

  return (
    <>
      <NavBar />
      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "column",
        }}
      >
        <div
          className="forma"
          style={{
            width: "400px",
            padding: "30px",
            borderRadius: "10px",
            backgroundColor: "rgba(255, 255, 255, 0.9)",
          }}
        >
          <form onSubmit={handleSubmit}>
            <span className="formaSpan">
              Unesite email
              <input
                type="email"
                onChange={(e) => setEmail(e.target.value)}
                ref={imeRef}
                required
                style={{
                  width: "100%",
                  padding: "10px",
                  marginTop: "5px",
                  marginBottom: "15px",
                  borderRadius: "5px",
                  border: "1px solid #ccc",
                }}
              />
            </span>

            <span className="formaSpan">
              Unesite lozinku
              <input
                type="password"
                onChange={(e) => setLozinka(e.target.value)}
                required
                style={{
                  width: "100%",
                  padding: "10px",
                  marginTop: "5px",
                  marginBottom: "25px",
                  borderRadius: "5px",
                  border: "1px solid #ccc",
                }}
              />
            </span>

            <button
              type="submit"
              className="btnNav"
              style={{
                width: "100%",
                height: "50px",
                backgroundColor: "#8a2be2",
                color: "white",
                border: "none",
                borderRadius: "5px",
                fontSize: "18px",
                cursor: "pointer",
              }}
            >
              Uloguj se
            </button>
          </form>
        </div>
      </div>

      <Footer />
    </>
  );
}
